/**
 * Modern QR Scanner untuk Scan Center
 * Menggantikan Instascan yang sudah deprecated
 */

class ModernQRScanner {
    constructor(videoElement, onScanCallback) {
        this.videoElement = videoElement;
        this.onScanCallback = onScanCallback;
        this.scanning = false;
        this.stream = null;
        this.canvas = document.createElement('canvas');
        this.canvasContext = this.canvas.getContext('2d');
        this.scanInterval = null;
    }

    async start() {
        try {
            const constraints = {
                video: {
                    facingMode: 'environment', // Use back camera
                    width: { ideal: 1280 },
                    height: { ideal: 720 }
                }
            };

            this.stream = await navigator.mediaDevices.getUserMedia(constraints);
            this.videoElement.srcObject = this.stream;

            return new Promise((resolve) => {
                this.videoElement.onloadedmetadata = () => {
                    this.videoElement.play();
                    this.startScanning();
                    resolve();
                };
            });
        } catch (error) {
            console.error('Error starting camera:', error);
            throw error;
        }
    }

    startScanning() {
        if (this.scanning) return;

        this.scanning = true;
        this.canvas.width = this.videoElement.videoWidth;
        this.canvas.height = this.videoElement.videoHeight;

        this.scanInterval = setInterval(() => {
            if (!this.scanning) return;

            this.canvasContext.drawImage(this.videoElement, 0, 0);
            const imageData = this.canvasContext.getImageData(0, 0, this.canvas.width, this.canvas.height);

            // Simple QR code detection (you might want to use a more robust library)
            this.detectQRCode(imageData);
        }, 500); // Scan every 500ms
    }

    detectQRCode(imageData) {
        // This is a simplified implementation
        // For production, consider using a dedicated QR library like jsQR
        // For now, we'll rely on manual input as fallback
    }

    stop() {
        this.scanning = false;

        if (this.scanInterval) {
            clearInterval(this.scanInterval);
            this.scanInterval = null;
        }

        if (this.stream) {
            this.stream.getTracks().forEach(track => track.stop());
            this.stream = null;
        }
    }

    isActive() {
        return this.scanning;
    }
}

// Fallback QR Scanner using jsQR library
class JSQRScanner {
    constructor(videoElement, onScanCallback) {
        this.videoElement = videoElement;
        this.onScanCallback = onScanCallback;
        this.scanning = false;
        this.stream = null;
        this.canvas = document.createElement('canvas');
        this.canvasContext = this.canvas.getContext('2d');
        this.scanInterval = null;
        this.lastScan = 0;
        this.scanDelay = 1000; // 1 second delay between scans
    }

    async start() {
        try {
            const constraints = {
                video: {
                    facingMode: 'environment',
                    width: { ideal: 1280 },
                    height: { ideal: 720 }
                }
            };

            this.stream = await navigator.mediaDevices.getUserMedia(constraints);
            this.videoElement.srcObject = this.stream;

            return new Promise((resolve) => {
                this.videoElement.onloadedmetadata = () => {
                    this.videoElement.play();
                    this.startScanning();
                    resolve();
                };
            });
        } catch (error) {
            console.error('Error starting camera:', error);
            throw error;
        }
    }

    startScanning() {
        if (this.scanning) return;
        this.scanning = true;

        this.scanInterval = setInterval(() => {
            if (!this.scanning) return;
            this.scanFrame();
        }, 200);
    }

    scanFrame() {
        if (!this.scanning || !this.videoElement.videoWidth) return;

        const now = Date.now();
        if (now - this.lastScan < this.scanDelay) return;

        this.canvas.width = this.videoElement.videoWidth;
        this.canvas.height = this.videoElement.videoHeight;
        this.canvasContext.drawImage(this.videoElement, 0, 0);

        const imageData = this.canvasContext.getImageData(0, 0, this.canvas.width, this.canvas.height);

        // Use jsQR if available
        if (typeof jsQR !== 'undefined') {
            const code = jsQR(imageData.data, imageData.width, imageData.height);
            if (code) {
                this.lastScan = now;
                this.onScanCallback(code.data);
            }
        }
    }

    stop() {
        this.scanning = false;

        if (this.scanInterval) {
            clearInterval(this.scanInterval);
            this.scanInterval = null;
        }

        if (this.stream) {
            this.stream.getTracks().forEach(track => track.stop());
            this.stream = null;
        }
    }

    isActive() {
        return this.scanning;
    }
}

// Export for use in scan_center.js
window.ModernQRScanner = ModernQRScanner;
window.JSQRScanner = JSQRScanner;